class UnionFind {
    constructor(size) {
        this.parent = Array.from({ length: size }, (_, i) => i);
        this.rank = new Array(size).fill(0);
    }

    find(u) {
        if (this.parent[u] !== u) {
            this.parent[u] = this.find(this.parent[u]);
        }
        return this.parent[u];
    }

    union(u, v) {
        const rootU = this.find(u);
        const rootV = this.find(v);
        if (rootU === rootV) return false;

        if (this.rank[rootU] > this.rank[rootV]) {
            this.parent[rootV] = rootU;
        } else if (this.rank[rootU] < this.rank[rootV]) {
            this.parent[rootU] = rootV;
        } else {
            this.parent[rootV] = rootU;
            this.rank[rootU]++;
        }
        return true;
    }
}

function solve(n, edges, k) {
    const mustEdges = [];
    const optionalEdges = [];

    for (const [u, v, s, must] of edges) {
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    const uf = new UnionFind(n);
    let components = n;

    // First, process all must edges
    for (const [u, v, s] of mustEdges) {
        if (uf.union(u, v)) {
            components--;
        }
    }

    if (components === 1) {
        // All nodes are connected by must edges, find the minimal strength
        let minStrength = Infinity;
        for (const [u, v, s] of mustEdges) {
            minStrength = Math.min(minStrength, s);
        }
        return minStrength;
    }

    // Now, process optional edges without upgrades first
    const sortedOptionalEdges = [...optionalEdges].sort((a, b) => b[2] - a[2]);
    const upgradedEdges = [];

    for (const [u, v, s] of sortedOptionalEdges) {
        if (uf.union(u, v)) {
            components--;
            upgradedEdges.push([u, v, s]);
        }
    }

    if (components > 1) {
        return -1;
    }

    // Now, we need to find the best edges to upgrade
    const allEdges = [...mustEdges, ...upgradedEdges];
    allEdges.sort((a, b) => a[2] - b[2]);

    let left = 0;
    let right = allEdges.length - 1;
    let result = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const targetStrength = allEdges[mid][2];

        const ufCheck = new UnionFind(n);
        let edgesUsed = 0;
        let upgradesUsed = 0;

        // Add must edges first
        for (const [u, v, s] of mustEdges) {
            ufCheck.union(u, v);
        }

        // Add optional edges with s >= targetStrength, possibly upgrading
        for (const [u, v, s] of optionalEdges) {
            if (s >= targetStrength) {
                if (ufCheck.union(u, v)) {
                    edgesUsed++;
                }
            } else if (s * 2 >= targetStrength && upgradesUsed < k) {
                if (ufCheck.union(u, v)) {
                    edgesUsed++;
                    upgradesUsed++;
                }
            }
        }

        // Check if all nodes are connected
        let root = ufCheck.find(0);
        let connected = true;
        for (let i = 1; i < n; i++) {
            if (ufCheck.find(i) !== root) {
                connected = false;
                break;
            }
        }

        if (connected && edgesUsed + mustEdges.length === n - 1 && upgradesUsed <= k) {
            result = targetStrength;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return result;
}

