#include <vector>
#include <algorithm>
using namespace std;

class UnionFind {
private:
    vector<int> parent;
    vector<int> rank;
public:
    UnionFind(int size) {
        parent.resize(size);
        rank.resize(size, 0);
        for (int i = 0; i < size; ++i) {
            parent[i] = i;
        }
    }

    int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    bool unionSet(int u, int v) {
        int rootU = find(u);
        int rootV = find(v);
        if (rootU == rootV) return false;

        if (rank[rootU] > rank[rootV]) {
            parent[rootV] = rootU;
        } else if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
        } else {
            parent[rootV] = rootU;
            rank[rootU]++;
        }
        return true;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    vector<vector<long long>> mustEdges;
    vector<vector<long long>> optionalEdges;

    for (const auto& edge : edges) {
        if (edge[3] == 1) {
            mustEdges.push_back({edge[0], edge[1], edge[2]});
        } else {
            optionalEdges.push_back({edge[0], edge[1], edge[2]});
        }
    }

    UnionFind uf(n);
    int components = n;

    // Process must edges first
    for (const auto& edge : mustEdges) {
        if (uf.unionSet(edge[0], edge[1])) {
            components--;
        }
    }

    if (components == 1) {
        long long minStrength = 1e18;
        for (const auto& edge : mustEdges) {
            minStrength = min(minStrength, edge[2]);
        }
        return minStrength;
    }

    // Process optional edges without upgrades
    sort(optionalEdges.begin(), optionalEdges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    vector<vector<long long>> upgradedEdges;
    for (const auto& edge : optionalEdges) {
        if (uf.unionSet(edge[0], edge[1])) {
            components--;
            upgradedEdges.push_back(edge);
        }
    }

    if (components > 1) {
        return -1;
    }

    // Combine must and upgraded edges
    vector<vector<long long>> allEdges;
    allEdges.insert(allEdges.end(), mustEdges.begin(), mustEdges.end());
    allEdges.insert(allEdges.end(), upgradedEdges.begin(), upgradedEdges.end());

    sort(allEdges.begin(), allEdges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    long long left = 0;
    long long right = allEdges.size() - 1;
    long long result = -1;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        long long targetStrength = allEdges[mid][2];

        UnionFind ufCheck(n);
        long long edgesUsed = 0;
        long long upgradesUsed = 0;

        // Add must edges
        for (const auto& edge : mustEdges) {
            ufCheck.unionSet(edge[0], edge[1]);
        }

        // Add optional edges
        for (const auto& edge : optionalEdges) {
            if (edge[2] >= targetStrength) {
                if (ufCheck.unionSet(edge[0], edge[1])) {
                    edgesUsed++;
                }
            } else if (edge[2] * 2 >= targetStrength && upgradesUsed < k) {
                if (ufCheck.unionSet(edge[0], edge[1])) {
                    edgesUsed++;
                    upgradesUsed++;
                }
            }
        }

        // Check connectivity
        int root = ufCheck.find(0);
        bool connected = true;
        for (int i = 1; i < n; ++i) {
            if (ufCheck.find(i) != root) {
                connected = false;
                break;
            }
        }

        if (connected && edgesUsed + mustEdges.size() == n - 1 && upgradesUsed <= k) {
            result = targetStrength;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return result;
}
