    vector<vector<long long>> mustEdges;
    vector<vector<long long>> optionalEdges;

    for (const auto& edge : edges) {
        if (edge[3] == 1) {
            mustEdges.push_back({edge[0], edge[1], edge[2]});
        } else {
            optionalEdges.push_back({edge[0], edge[1], edge[2]});
        }
    }

    UnionFind uf(n);
    long long components = n;

    // Process must edges first
    for (const auto& edge : mustEdges) {
        if (uf.unionSet(edge[0], edge[1])) {
            components--;
        }
    }

    if (components == 1) {
        long long minStrength = 1e18;
        for (const auto& edge : mustEdges) {
            minStrength = min(minStrength, edge[2]);
        }
        return minStrength;
    }

    // Process optional edges without upgrades
    sort(optionalEdges.begin(), optionalEdges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
